import{_ as a,o,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"43. Accrued Days Off","description":"","frontmatter":{"title":"43. Accrued Days Off","eba":"Nurses and Midwives 2024-2028","topics":["hours","rosters","staffing"]},"headers":[],"relativePath":"ebas/nurses-midwives/hours-of-work/43-accrued-days-off.md","filePath":"ebas/nurses-midwives/hours-of-work/43-accrued-days-off.md"}'),s={name:"ebas/nurses-midwives/hours-of-work/43-accrued-days-off.md"};function n(i,e,l,h,p,c){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_43-accrued-days-off" tabindex="-1">43. Accrued Days Off <a class="header-anchor" href="#_43-accrued-days-off" aria-label="Permalink to &quot;43. Accrued Days Off&quot;">​</a></h1><p><strong>43.1</strong> Accrual of ADOs</p><p>Unless the workload management arrangements have been varied in accordance with this Agreement, all full-time Employees will accrue an ADO as follows:</p><p><strong>(a)</strong> a full-time Employee rostered to work on shifts of eight hours&#39; duration will work 152 hours in each four-week roster cycle to be worked as 19 days each of eight hours with an ADO in each four week roster cycle; and</p><p><strong>(b)</strong> a full-time Employee rostered to work on night shifts of ten hours&#39; duration will work 190 hours in each five-week roster cycle to be worked as 19 shifts each of 10 hours with an ADO in each five week roster cycle.</p><p><strong>43.2</strong> Taking of ADOs</p><p>Wherever practicable, an ADO will be on the date requested by the Employee.</p><p><strong>43.3</strong> Maximum number of ADOs</p><p>The maximum number of ADOs which may be accrued in any calendar year is thirteen.</p><p><strong>43.4</strong> ADOs and annual leave</p><p>See also <a href="/eba/ebas/nurses-midwives/leave/57-annual-leave.html">clause 57</a> (Annual Leave).</p><p>One day of a year&#39;s annual leave period will be regarded as an accrued day off for which no additional payment is to be made.</p><p><strong>43.5</strong> ADOs on public holidays</p><p>See also <a href="/eba/ebas/medical-specialists/leave/56-public-holidays.html">clause 56</a> (Public Holidays).</p><p>Where a public holiday falls on a day upon which the Employee is on an ADO, another day will be determined by the Employer to be taken by the Employee in lieu of the public holiday, such day to be within the same work cycle where practical.</p><p><strong>43.6</strong> ADOs and short shifts</p><p>If a full-time Employee works a short shift, that Employee will be entitled to an ADO as if a full shift was worked.</p><p><strong>43.7</strong> ADOs and termination of employment</p><p>Upon termination of employment if the Employee has:</p><p><strong>(a)</strong> taken an ADO (in part or whole) in advance of accruing the necessary hours, the salary of the Employee will be reduced by the total ADOs or portion taken in advance; and</p><p><strong>(b)</strong> untaken ADOs (in part or whole) at the time of termination, the Employee will be paid the untaken ADOs.</p><p><strong>43.8</strong> ADOs and reduction in ordinary hours</p><p>Where an Employee reduces their ordinary hours and the Employee has:</p><p><strong>(a)</strong> taken an ADO (in part or whole) in advance of accruing the necessary hours, the salary of the Employee of the Employee will be reduced by the total ADOs or portion taken in advance; and</p><p><strong>(b)</strong> untaken ADOs (in part or whole) at the time of the reduction in ordinary hours, the Employee will elect to either be paid out the ADOs, take the ADOs at a time agreed with the Employer or a combination of both.</p><p>Plain language terms: ADO, RDO, accrued day.</p>',26)])])}const f=a(s,[["render",n]]);export{u as __pageData,f as default};
